# capacity_validation.py — PI Planning capacity vs. budget gate
from dataclasses import dataclass

@dataclass
class TeamCapacityCommitment:
    team: str
    sprint_count: int
    daily_token_estimate: int    # average input tokens per day during this PI

@dataclass
class PICapacityPlan:
    commitments: list[TeamCapacityCommitment]
    daily_org_quota: int         # total input tokens per day from API agreement

def validate_capacity(plan: PICapacityPlan) -> dict:
    total_daily = sum(c.daily_token_estimate for c in plan.commitments)
    utilisation = total_daily / plan.daily_org_quota
    per_team = {c.team: c.daily_token_estimate for c in plan.commitments}
    issues = []
    if utilisation > 0.90:
        issues.append(f"Aggregate utilisation {utilisation:.0%} exceeds 90% safety threshold")
    for c in plan.commitments:
        team_util = c.daily_token_estimate / plan.daily_org_quota
        if team_util > 0.40:
            issues.append(f"{c.team} claims {team_util:.0%} of org quota — concentration risk")
    return {
        "total_daily_tokens": total_daily,
        "org_quota": plan.daily_org_quota,
        "utilisation_pct": round(utilisation * 100, 1),
        "per_team": per_team,
        "issues": issues,
        "verdict": "PASS" if not issues else "REVIEW REQUIRED",
    }

plan = PICapacityPlan(
    commitments=[
        TeamCapacityCommitment("Team Alpha", 5, 1_200_000),
        TeamCapacityCommitment("Team Beta",  5,   900_000),
        TeamCapacityCommitment("Team Gamma", 5,   600_000),
    ],
    daily_org_quota=3_000_000,
)
result = validate_capacity(plan)
print(f"Verdict: {result['verdict']}")
print(f"Utilisation: {result['utilisation_pct']}%")
for issue in result["issues"]:
    print(f"  ! {issue}")
